package com.enterprise.auth.service;

import org.springframework.stereotype.Component;

import java.security.SecureRandom;
import java.util.ArrayList;
import java.util.List;

@Component
public class BackupCodeGenerator {

    private static final String CHARACTERS = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
    private static final int CODE_SEGMENT_LENGTH = 4;
    private static final int CODE_SEGMENTS = 3;
    private static final int DEFAULT_CODE_COUNT = 10;
    private final SecureRandom secureRandom;

    public BackupCodeGenerator() {
        this.secureRandom = new SecureRandom();
    }

    public List<String> generateBackupCodes() {
        return generateBackupCodes(DEFAULT_CODE_COUNT);
    }

    public List<String> generateBackupCodes(int count) {
        if (count < 1 || count > 20) {
            throw new IllegalArgumentException("Code count must be between 1 and 20");
        }

        List<String> codes = new ArrayList<>();
        for (int i = 0; i < count; i++) {
            codes.add(generateSingleCode());
        }
        return codes;
    }

    private String generateSingleCode() {
        StringBuilder code = new StringBuilder();
        for (int segment = 0; segment < CODE_SEGMENTS; segment++) {
            if (segment > 0) {
                code.append('-');
            }
            for (int i = 0; i < CODE_SEGMENT_LENGTH; i++) {
                int index = secureRandom.nextInt(CHARACTERS.length());
                code.append(CHARACTERS.charAt(index));
            }
        }
        return code.toString();
    }
}

