package com.enterprise.auth.service;

import com.enterprise.auth.entity.User;
import com.enterprise.auth.exception.AccountLockedException;
import com.enterprise.auth.repository.UserRepository;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.LocalDateTime;

@Service
@RequiredArgsConstructor
@Slf4j
public class AccountLockService {

    private final UserRepository userRepository;

    @Value("${auth.max-failed-attempts:5}")
    private int maxFailedAttempts;

    @Value("${auth.lock-duration-minutes:30}")
    private int lockDurationMinutes;

    public void checkAccountLock(User user) {
        if (user.isAccountLocked()) {
            if (user.getLockTime() != null &&
                user.getLockTime().plusMinutes(lockDurationMinutes).isBefore(LocalDateTime.now())) {
                unlockAccount(user);
            } else {
                throw new AccountLockedException(
                    "Account is locked due to too many failed attempts. Please try again later.");
            }
        }
    }

    @Transactional
    public void recordFailedAttempt(User user) {
        int attempts = user.getFailedLoginAttempts() + 1;
        user.setFailedLoginAttempts(attempts);

        if (attempts >= maxFailedAttempts) {
            user.setAccountLocked(true);
            user.setLockTime(LocalDateTime.now());
            log.warn("Account locked for user: {} after {} failed attempts", user.getUsername(), attempts);
        }

        userRepository.save(user);
    }

    @Transactional
    public void resetFailedAttempts(User user) {
        user.setFailedLoginAttempts(0);
        user.setAccountLocked(false);
        user.setLockTime(null);
        userRepository.save(user);
    }

    private void unlockAccount(User user) {
        user.setAccountLocked(false);
        user.setFailedLoginAttempts(0);
        user.setLockTime(null);
        userRepository.save(user);
        log.info("Account unlocked for user: {} after lock duration expired", user.getUsername());
    }
}

// src/main/java/com/enterprise/auth/service/MfaService.java
package com.enterprise.auth.service;

import com.enterprise.auth.dto.*;
import com.enterprise.auth.entity.BackupCode;
import com.enterprise.auth.entity.User;
import com.enterprise.auth.exception.AuthenticationException;
import com.enterprise.auth.exception.MfaException;
import com.enterprise.auth.exception.UserNotFoundException;
import com.enterprise.auth.repository.BackupCodeRepository;
import com.enterprise.auth.repository.UserRepository;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.security.SecureRandom;
import java.time.LocalDateTime;
import java.util.Base64;
import java.util.List;

@Service
@RequiredArgsConstructor
@Slf4j
public class MfaService {

    private final UserRepository userRepository;
    private final BackupCodeRepository backupCodeRepository;
    private final BackupCodeGenerator backupCodeGenerator;
    private final PasswordEncoder passwordEncoder;
    private final AuditService auditService;
    private final AccountLockService accountLockService;

    @Value("${auth.backup-code.expiry-days:365}")
    private int backupCodeExpiryDays;

    @Value("${auth.backup-code.regenerate-threshold:3}")
    private int regenerateThreshold;

    @Transactional
    public EnableMfaResponse enableMfa(EnableMfaRequest request, String ipAddress, String userAgent) {
        User user = userRepository.findByUsername(request.getUsername())
                .orElseThrow(() -> new UserNotFoundException("User not found"));

        accountLockService.checkAccountLock(user);

        if (!passwordEncoder.matches(request.getPassword(), user.getPassword())) {
            accountLockService.recordFailedAttempt(user);
            auditService.logEvent(user.getId(), "MFA_ENABLE_FAILED", "Invalid password", ipAddress, userAgent, false);
            throw new AuthenticationException("Invalid credentials");
        }

        if (user.isMfaEnabled()) {
            throw new MfaException("MFA is already enabled for this account");
        }

        // Generate MFA secret
        String mfaSecret = generateMfaSecret();
        user.setMfaSecret(passwordEncoder.encode(mfaSecret));
        user.setMfaEnabled(true);

        // Delete any existing backup codes
        backupCodeRepository.deleteAllByUser(user);

        // Generate new backup codes
        List<String> plainTextCodes = backupCodeGenerator.generateBackupCodes();
        LocalDateTime expiresAt = LocalDateTime.now().plusDays(backupCodeExpiryDays);

        for (String code : plainTextCodes) {
            BackupCode backupCode = BackupCode.builder()
                    .user(user)
                    .codeHash(passwordEncoder.encode(code))
                    .used(false)
                    .expiresAt(expiresAt)
                    .build();
            backupCodeRepository.save(backupCode);
        }

        accountLockService.resetFailedAttempts(user);
        userRepository.save(user);

        auditService.logEvent(user.getId(), "MFA_ENABLED", "MFA enabled with backup codes generated", ipAddress, userAgent, true);

        log.info("MFA enabled for user: {}", user.getUsername());

        return EnableMfaResponse.builder()
                .mfaSecret(mfaSecret)
                .backupCodes(plainTextCodes)
                .message("MFA has been enabled. Please save your backup codes securely. They will not be shown again.")
                .build();
    }

    @Transactional
    public AuthResponse authenticateWithBackupCode(BackupCodeAuthRequest request, String ipAddress, String userAgent) {
        User user = userRepository.findByUsername(request.getUsername())
                .orElseThrow(() -> new UserNotFoundException("User not found"));

        accountLockService.checkAccountLock(user);

        // Verify password first
        if (!passwordEncoder.matches(request.getPassword(), user.getPassword())) {
            accountLockService.recordFailedAttempt(user);
            auditService.logEvent(user.getId(), "BACKUP_CODE_AUTH_FAILED", "Invalid password", ipAddress, userAgent, false);
            throw new AuthenticationException("Invalid credentials");
        }

        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA is not enabled for this account");
        }

        // Get valid (unused, non-expired) backup codes
        List<BackupCode> validCodes = backupCodeRepository.findValidBackupCodes(user);

        if (validCodes.isEmpty()) {
            auditService.logEvent(user.getId(), "BACKUP_CODE_AUTH_FAILED", "No valid backup codes available", ipAddress, userAgent, false);
            throw new MfaException("No valid backup codes available. Please contact support.");
        }

        // Check the provided backup code against stored hashes
        String providedCode = request.getBackupCode().trim().toUpperCase();
        BackupCode matchedCode = null;

        for (BackupCode storedCode : validCodes) {
            if (passwordEncoder.matches(providedCode, storedCode.getCodeHash())) {
                matchedCode = storedCode;
                break;
            }
        }

        if (matchedCode == null) {
            accountLockService.recordFailedAttempt(user);
            auditService.logEvent(user.getId(), "BACKUP_CODE_AUTH_FAILED", "Invalid backup code", ipAddress, userAgent, false);
            throw new AuthenticationException("Invalid backup code");
        }

        // Mark the backup code as used
        matchedCode.setUsed(true);
        matchedCode.setUsedAt(LocalDateTime.now());
        backupCodeRepository.save(matchedCode);

        accountLockService.resetFailedAttempts(user);

        long remainingCodes = backupCodeRepository.countValidBackupCodes(user);

        auditService.logEvent(user.getId(), "BACKUP_CODE_AUTH_SUCCESS",
                String.format("Backup code used. Remaining: %d", remainingCodes), ipAddress, userAgent, true);

        log.info("User {} authenticated with backup code. Remaining codes: {}", user.getUsername(), remainingCodes);

        String warningMessage = "";
        if (remainingCodes <= regenerateThreshold) {
            warningMessage = String.format(" WARNING: Only %d backup codes remaining. Please regenerate your backup codes.", remainingCodes);
        }

        return AuthResponse.builder()
                .success(true)
                .message("Authentication successful using backup code." + warningMessage)
                .token(generateSessionToken())
                .remainingBackupCodes((int) remainingCodes)
                .build();
    }

    @Transactional
    public EnableMfaResponse regenerateBackupCodes(RegenerateCodesRequest request, String ipAddress, String userAgent) {
        User user = userRepository.findByUsername(request.getUsername())
                .orElseThrow(() -> new UserNotFoundException("User not found"));

        accountLockService.checkAccountLock(user);

        if (!passwordEncoder.matches(request.getPassword(), user.getPassword())) {
            accountLockService.recordFailedAttempt(user);
            auditService.logEvent(user.getId(), "BACKUP_CODE_REGEN_FAILED", "Invalid password", ipAddress, userAgent, false);
            throw new AuthenticationException("Invalid credentials");
        }

        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA is not enabled for this account");
        }

        // Delete all existing backup codes
        backupCodeRepository.deleteAllByUser(user);

        // Generate new backup codes
        List<String> plainTextCodes = backupCodeGenerator.generateBackupCodes();
        LocalDateTime expiresAt = LocalDateTime.now().plusDays(backupCodeExpiryDays);

        for (String code : plainTextCodes) {
            BackupCode backupCode = BackupCode.builder()
                    .user(user)
                    .codeHash(passwordEncoder.encode(code))
                    .used(false)
                    .expiresAt(expiresAt)
                    .build();
            backupCodeRepository.save(backupCode);
        }

        accountLockService.resetFailedAttempts(user);

        auditService.logEvent(user.getId(), "BACKUP_CODES_REGENERATED", "New backup codes generated", ipAddress, userAgent, true);

        log.info("Backup codes regenerated for user: {}", user.getUsername());

        return EnableMfaResponse.builder()
                .backupCodes(plainTextCodes)
                .message("New backup codes have been generated. Previous codes are now invalid. Please save these securely.")
                .build();
    }

    public BackupCodeStatusResponse getBackupCodeStatus(String username) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new UserNotFoundException("User not found"));

        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA is not enabled for this account");
        }

        long validCodes = backupCodeRepository.countValidBackupCodes(user);
        List<BackupCode> allCodes = backupCodeRepository.findByUserAndUsedFalse(user);
        long totalGenerated = user.getBackupCodes().size();
        long usedCodes = totalGenerated - allCodes.size();

        return BackupCodeStatusResponse.builder()
                .totalCodes(totalGenerated)
                .remainingCodes(validCodes)
                .usedCodes(usedCodes)
                .shouldRegenerate(validCodes <= regenerateThreshold)
                .message(validCodes <= regenerateThreshold ?
                        "You have few backup codes remaining. Consider regenerating them." :
                        "Backup codes are available.")
                .build();
    }

    @Transactional
    public void disableMfa(String username, String password, String ipAddress, String userAgent) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new UserNotFoundException("User not found"));

        accountLockService.checkAccountLock(user);

        if (!passwordEncoder.matches(password, user.getPassword())) {
            accountLockService.recordFailedAttempt(user);
            auditService.logEvent(user.getId(), "MFA_DISABLE_FAILED", "Invalid password", ipAddress, userAgent, false);
            throw new AuthenticationException("Invalid credentials");
        }

        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA is not enabled for this account");
        }

        // Delete all backup codes
        backupCodeRepository.deleteAllByUser(user);

        user.setMfaEnabled(false);
        user.setMfaSecret(null);
        userRepository.save(user);

        accountLockService.resetFailedAttempts(user);

        auditService.logEvent(user.getId(), "MFA_DISABLED", "MFA disabled and backup codes removed", ipAddress, userAgent, true);

        log.info("MFA disabled for user: {}", user.getUsername());
    }

    private String generateMfaSecret() {
        SecureRandom secureRandom = new SecureRandom();
        byte[] secretBytes = new byte[20];
        secureRandom.nextBytes(secretBytes);
        return Base64.getEncoder().withoutPadding().encodeToString(secretBytes);
    }

    private String generateSessionToken() {
        SecureRandom secureRandom = new SecureRandom();
        byte[] tokenBytes = new byte[32];
        secureRandom.nextBytes(tokenBytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(tokenBytes);
    }
}

