package com.enterprise.auth.controller;

import com.enterprise.auth.dto.*;
import com.enterprise.auth.service.MfaService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.validation.Valid;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/v1/mfa")
@RequiredArgsConstructor
@Slf4j
public class MfaController {

    private final MfaService mfaService;

    @PostMapping("/enable")
    public ResponseEntity<EnableMfaResponse> enableMfa(
            @Valid @RequestBody EnableMfaRequest request,
            HttpServletRequest httpRequest) {
        String ipAddress = getClientIpAddress(httpRequest);
        String userAgent = httpRequest.getHeader("User-Agent");

        EnableMfaResponse response = mfaService.enableMfa(request, ipAddress, userAgent);
        return ResponseEntity.status(HttpStatus.CREATED).body(response);
    }

    @PostMapping("/authenticate/backup-code")
    public ResponseEntity<AuthResponse> authenticateWithBackupCode(
            @Valid @RequestBody BackupCodeAuthRequest request,
            HttpServletRequest httpRequest) {
        String ipAddress = getClientIpAddress(httpRequest);
        String userAgent = httpRequest.getHeader("User-Agent");

        AuthResponse response = mfaService.authenticateWithBackupCode(request, ipAddress, userAgent);
        return ResponseEntity.ok(response);
    }

    @PostMapping("/backup-codes/regenerate")
    public ResponseEntity<EnableMfaResponse> regenerateBackupCodes(
            @Valid @RequestBody RegenerateCodesRequest request,
            HttpServletRequest httpRequest) {
        String ipAddress = getClientIpAddress(httpRequest);
        String userAgent = httpRequest.getHeader("User-Agent");

        EnableMfaResponse response = mfaService.regenerateBackupCodes(request, ipAddress, userAgent);
        return ResponseEntity.ok(response);
    }

    @GetMapping("/backup-codes/status/{username}")
    public ResponseEntity<BackupCodeStatusResponse> getBackupCodeStatus(@PathVariable String username) {
        BackupCodeStatusResponse response = mfaService.getBackupCodeStatus(username);
        return ResponseEntity.ok(response);
    }

    @PostMapping("/disable")
    public ResponseEntity<Void> disableMfa(
            @Valid @RequestBody EnableMfaRequest request,
            HttpServletRequest httpRequest) {
        String ipAddress = getClientIpAddress(httpRequest);
        String userAgent = httpRequest.getHeader("User-Agent");

        mfaService.disableMfa(request.getUsername(), request.getPassword(), ipAddress, userAgent);
        return ResponseEntity.noContent().build();
    }

    private String getClientIpAddress(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            // Take the first IP in the chain (original client)
            String ip = xForwardedFor.split(",")[0].trim();
            // Basic validation to prevent header injection
            if (ip.matches("^[0-9a-fA-F.:]+$") && ip.length() <= 45) {
                return ip;
            }
        }
        return request.getRemoteAddr();
    }
}

