// src/test/java/com/enterprise/auth/service/BackupCodeGeneratorTest.java
package com.enterprise.auth.service;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.util.HashSet;
import java.util.List;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;

class BackupCodeGeneratorTest {

    private BackupCodeGenerator backupCodeGenerator;

    @BeforeEach
    void setUp() {
        backupCodeGenerator = new BackupCodeGenerator();
    }

    @Test
    void shouldGenerateDefaultNumberOfCodes() {
        List<String> codes = backupCodeGenerator.generateBackupCodes();
        assertEquals(10, codes.size());
    }

    @Test
    void shouldGenerateSpecifiedNumberOfCodes() {
        List<String> codes = backupCodeGenerator.generateBackupCodes(5);
        assertEquals(5, codes.size());
    }

    @Test
    void shouldGenerateCodesInCorrectFormat() {
        List<String> codes = backupCodeGenerator.generateBackupCodes();
        for (String code : codes) {
            assertTrue(code.matches("^[A-Z0-9]{4}-[A-Z0-9]{4}-[A-Z0-9]{4}$"),
                    "Code should match format XXXX-XXXX-XXXX: " + code);
        }
    }

    @Test
    void shouldGenerateUniqueCodes() {
        List<String> codes = backupCodeGenerator.generateBackupCodes(20);
        Set<String> uniqueCodes = new HashSet<>(codes);
        assertEquals(codes.size(), uniqueCodes.size(), "All generated codes should be unique");
    }

    @Test
    void shouldThrowExceptionForInvalidCount() {
        assertThrows(IllegalArgumentException.class, () -> backupCodeGenerator.generateBackupCodes(0));
        assertThrows(IllegalArgumentException.class, () -> backupCodeGenerator.generateBackupCodes(21));
    }
}

// src/test/java/com/enterprise/auth/service/MfaServiceTest.java
package com.enterprise.auth.service;

import com.enterprise.auth.dto.*;
import com.enterprise.auth.entity.BackupCode;
import com.enterprise.auth.entity.User;
import com.enterprise.auth.exception.AuthenticationException;
import com.enterprise.auth.exception.MfaException;
import com.enterprise.auth.repository.BackupCodeRepository;
import com.enterprise.auth.repository.UserRepository;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.test.util.ReflectionTestUtils;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;
import java.util.Optional;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.ArgumentMatchers.*;
import static org.mockito.Mockito.*;

@ExtendWith(MockitoExtension.class)
class MfaServiceTest {

    @Mock
    private UserRepository userRepository;

    @Mock
    private BackupCodeRepository backupCodeRepository;

    @Mock
    private BackupCodeGenerator backupCodeGenerator;

    @Mock
    private PasswordEncoder passwordEncoder;

    @Mock
    private AuditService auditService;

    @Mock
    private AccountLockService accountLockService;

    @InjectMocks
    private MfaService mfaService;

    private User testUser;

    @BeforeEach
    void setUp() {
        ReflectionTestUtils.setField(mfaService, "backupCodeExpiryDays", 365);
        ReflectionTestUtils.setField(mfaService, "regenerateThreshold", 3);

        testUser = User.builder()
                .id(1L)
                .username("testuser")
                .email("test@enterprise.com")
                .password("hashedPassword")
                .mfaEnabled(false)
                .accountLocked(false)
                .failedLoginAttempts(0)
                .backupCodes(new ArrayList<>())
                .build();
    }

    @Test
    void shouldEnableMfaSuccessfully() {
        EnableMfaRequest request = new EnableMfaRequest();
        request.setUsername("testuser");
        request.setPassword("password");

        when(userRepository.findByUsername("testuser")).thenReturn(Optional.of(testUser));
        when(passwordEncoder.matches("password", "hashedPassword")).thenReturn(true);
        when(passwordEncoder.encode(anyString())).thenReturn("encodedValue");
        when(backupCodeGenerator.generateBackupCodes()).thenReturn(
                List.of("ABCD-EFGH-IJKL", "MNOP-QRST-UVWX"));
        when(backupCodeRepository.save(any(BackupCode.class))).thenAnswer(i -> i.getArgument(0));
        when(userRepository.save(any(User.class))).thenReturn(testUser);

        EnableMfaResponse response = mfaService.enableMfa(request, "127.0.0.1", "TestAgent");

        assertNotNull(response);
        assertNotNull(response.getMfaSecret());
        assertEquals(2, response.getBackupCodes().size());
        assertTrue(testUser.isMfaEnabled());
        verify(backupCodeRepository, times(2)).save(any(BackupCode.class));
    }

    @Test
    void shouldFailEnableMfaWithWrongPassword() {
        EnableMfaRequest request = new EnableMfaRequest();
        request.setUsername("testuser");
        request.setPassword("wrongpassword");

        when(userRepository.findByUsername("testuser")).thenReturn(Optional.of(testUser));
        when(passwordEncoder.matches("wrongpassword", "hashedPassword")).thenReturn(false);

        assertThrows(AuthenticationException.class,
                () -> mfaService.enableMfa(request, "127.0.0.1", "TestAgent"));
    }

    @Test
    void shouldFailEnableMfaWhenAlreadyEnabled() {
        testUser.setMfaEnabled(true);

        EnableMfaRequest request = new EnableMfaRequest();
        request.setUsername("testuser");
        request.setPassword("password");

        when(userRepository.findByUsername("testuser")).thenReturn(Optional.of(testUser));
        when(passwordEncoder.matches("password", "hashedPassword")).thenReturn(true);

        assertThrows(MfaException.class,
                () -> mfaService.enableMfa(request, "127.0.0.1", "TestAgent"));
    }

    @Test
    void shouldAuthenticateWithValidBackupCode() {
        testUser.setMfaEnabled(true);

        BackupCodeAuthRequest request = new BackupCodeAuthRequest();
        request.setUsername("testuser");
        request.setPassword("password");
        request.setBackupCode("ABCD-EFGH-IJKL");

        BackupCode storedCode = BackupCode.builder()
                .id(1L)
                .user(testUser)
                .codeHash("hashedCode")
                .used(false)
                .expiresAt(LocalDateTime.now().plusDays(365))
                .build();

        when(userRepository.findByUsername("testuser")).thenReturn(Optional.of(testUser));
        when(passwordEncoder.matches("password", "hashedPassword")).thenReturn(true);
        when(backupCodeRepository.findValidBackupCodes(testUser)).thenReturn(List.of(storedCode));
        when(passwordEncoder.matches("ABCD-EFGH-IJKL", "hashedCode")).thenReturn(true);
        when(backupCodeRepository.save(any(BackupCode.class))).thenReturn(storedCode);
        when(backupCodeRepository.countValidBackupCodes(testUser)).thenReturn(9L);

        AuthResponse response = mfaService.authenticateWithBackupCode(request, "127.0.0.1", "TestAgent");

        assertTrue(response.isSuccess());
        assertNotNull(response.getToken());
        assertEquals(9, response.getRemainingBackupCodes());
        assertTrue(storedCode.isUsed());
        assertNotNull(storedCode.getUsedAt());
    }

    @Test
    void shouldFailAuthenticationWithInvalidBackupCode() {
        testUser.setMfaEnabled(true);

        BackupCodeAuthRequest request = new BackupCodeAuthRequest();
        request.setUsername("testuser");
        request.setPassword("password");
        request.setBackupCode("XXXX-XXXX-XXXX");

        BackupCode storedCode = BackupCode.builder()
                .id(1L)
                .user(testUser)
                .codeHash("hashedCode")
                .used(false)
                .expiresAt(LocalDateTime.now().plusDays(365))
                .build();

        when(userRepository.findByUsername("testuser")).thenReturn(Optional.of(testUser));
        when(passwordEncoder.matches("password", "hashedPassword")).thenReturn(true);
        when(backupCodeRepository.findValidBackupCodes(testUser)).thenReturn(List.of(storedCode));
        when(passwordEncoder.matches("XXXX-XXXX-XXXX", "hashedCode")).thenReturn(false);

        assertThrows(AuthenticationException.class,
                () -> mfaService.authenticateWithBackupCode(request, "127.0.0.1", "TestAgent"));
    }

    @Test
    void shouldRegenerateBackupCodes() {
        testUser.setMfaEnabled(true);

        RegenerateCodesRequest request = new RegenerateCodesRequest();
        request.setUsername("testuser");
        request.setPassword("password");

        when(userRepository.findByUsername("testuser")).thenReturn(Optional.of(testUser));
        when(passwordEncoder.matches("password", "hashedPassword")).thenReturn(true);
        when(backupCodeGenerator.generateBackupCodes()).thenReturn(
                List.of("NEW1-CODE-HERE", "NEW2-CODE-HERE"));
        when(passwordEncoder.encode(anyString())).thenReturn("newHashedCode");
        when(backupCodeRepository.save(any(BackupCode.class))).thenAnswer(i -> i.getArgument(0));

        EnableMfaResponse response = mfaService.regenerateBackupCodes(request, "127.0.0.1", "TestAgent");

        assertNotNull(response);
        assertEquals(2, response.getBackupCodes().size());
        verify(backupCodeRepository).deleteAllByUser(testUser);
        verify(backupCodeRepository, times(2)).save(any(BackupCode.class));
    }

    @Test
    void shouldWarnWhenFewBackupCodesRemaining() {
        testUser.setMfaEnabled(true);

        BackupCodeAuthRequest request = new BackupCodeAuthRequest();
        request.setUsername("testuser");
        request.setPassword("password");
        request.setBackupCode("ABCD-EFGH-IJKL");

        BackupCode storedCode = BackupCode.builder()
                .id(1L)
                .user(testUser)
                .codeHash("hashedCode")
                .used(false)
                .expiresAt(LocalDateTime.now().plusDays(365))
                .build();

        when(userRepository.findByUsername("testuser")).thenReturn(Optional.of(testUser));
        when(passwordEncoder.matches("password", "hashedPassword")).thenReturn(true);
        when(backupCodeRepository.findValidBackupCodes(testUser)).thenReturn(List.of(storedCode));
        when(passwordEncoder.matches("ABCD-EFGH-IJKL", "hashedCode")).thenReturn(true);
        when(backupCodeRepository.save(any(BackupCode.class))).thenReturn(storedCode);
        when(backupCodeRepository.countValidBackupCodes(testUser)).thenReturn(2L);

        AuthResponse response = mfaService.authenticateWithBackupCode(request, "127.0.0.1", "TestAgent");

        assertTrue(response.getMessage().contains("WARNING"));
        assertEquals(2, response.getRemainingBackupCodes());
    }
}